"""LandTransport (TOPIX-33 sector 5200) — '2025 Q4' four-section narratives, 2-WEEK stock metric.

"2025 Q4 report" == the FY2025 full-year report (fiscal year that ENDED in 2025):
  March end -> FY3/2025 ; December end -> FY12/2025.
STOCK DIRECTION = the market's reaction to THIS report: close on the earnings-announcement date
(pre-news baseline; JP tanshin released after the 15:00 close) vs close ~2 weeks later.
REVENUE DIRECTION = revenue stated in the FY2025 report, YoY vs FY2024.
Narrative = the full FOUR-SECTION "lighter prompt", written qualitatively and plainly. Point-in-time:
narratives use the FY2025 report (incl. the guidance issued WITH it) + earlier years only.
"""
from __future__ import annotations


def S(ov, biz, whybiz, whystk):
    return (f"**Company overview:** {ov}\n\n**How did business move?** {biz}\n\n"
            f"**Why did business move this way?** {whybiz}\n\n**Why did the stock move this way?** {whystk}")


def SJ(ov, biz, whybiz, whystk):
    return (f"**会社概要:** {ov}\n\n**業績の動き:** {biz}\n\n"
            f"**業績が動いた理由:** {whybiz}\n\n**株価が動いた理由:** {whystk}")


